import { readFileSync } from 'fs';
import { join } from 'path';
import type { TCGPlayerProductDetails, Edition } from '@/types';

const BASE_URL = 'https://mp-search-api.tcgplayer.com/v1';
const IMAGE_BASE_URL = 'https://product-images.tcgplayer.com/fit-in/437x437';

// Load TCGdex → TCGPlayer set name mapping (generated by discover-tcgplayer-sets.ts)
let tcgplayerSetMap: Record<string, string> = {};
try {
  const mapPath = join(__dirname, 'tcgplayer-set-map.json');
  tcgplayerSetMap = JSON.parse(readFileSync(mapPath, 'utf-8'));
} catch {
  // Map file doesn't exist yet — will be generated by discovery script
}

// Strip common TCGPlayer set name prefixes for better matching
const TCGPLAYER_SET_PREFIXES = /^(SV:\s*|SWSH:\s*|SM:\s*|XY:\s*|BW:\s*|HS:\s*|SV\s+|SWSH\s+|SM\s+|XY\s+|BW\s+|Pokémon\s+TCG\s+)/i;

export function getProductImageUrl(productId: number): string {
  return `${IMAGE_BASE_URL}/${productId}.jpg`;
}

export function getTcgplayerProductUrl(
  productUrlName: string,
  productId: number
): string {
  return `https://www.tcgplayer.com/product/${productId}/pokemon-${productUrlName}`;
}

export async function getProductDetails(
  productId: number
): Promise<TCGPlayerProductDetails | null> {
  try {
    const res = await fetch(`${BASE_URL}/product/${productId}/details`, {
      headers: {
        Accept: 'application/json',
      },
    });

    if (!res.ok) return null;

    const data = await res.json();

    return {
      productId: data.productId,
      productName: data.productName,
      marketPrice: data.marketPrice ?? null,
      lowestPrice: data.lowestPrice ?? null,
      medianPrice: data.medianPrice ?? null,
      lowestPriceWithShipping: data.lowestPriceWithShipping ?? null,
      imageCount: data.imageCount ?? 0,
      setName: data.setName ?? '',
      setUrlName: data.setUrlName ?? '',
      productUrlName: data.productUrlName ?? '',
      productTypeName: data.productTypeName ?? '',
      activeListings: data.activeListings ?? 0,
      sellers: data.sellers ?? 0,
    };
  } catch {
    return null;
  }
}

export async function getProductDetailsBatch(
  productIds: number[],
  concurrency = 5
): Promise<Map<number, TCGPlayerProductDetails>> {
  const results = new Map<number, TCGPlayerProductDetails>();

  // Process in batches to limit concurrency
  for (let i = 0; i < productIds.length; i += concurrency) {
    const batch = productIds.slice(i, i + concurrency);
    const details = await Promise.all(batch.map(getProductDetails));
    for (let j = 0; j < batch.length; j++) {
      if (details[j] != null) {
        results.set(batch[j], details[j]!);
      }
    }
  }

  return results;
}

function getEditionSearchTerms(edition?: Edition | null): string {
  switch (edition) {
    case '1st-edition':
      return ' 1st edition';
    case 'shadowless':
      return ' shadowless';
    case 'unlimited':
      return ' unlimited';
    default:
      return '';
  }
}

function matchesEdition(
  productName: string,
  edition?: Edition | null
): boolean {
  const lower = productName.toLowerCase();
  switch (edition) {
    case '1st-edition':
      return lower.includes('1st edition');
    case 'shadowless':
      return lower.includes('shadowless');
    case 'unlimited':
      return lower.includes('unlimited') || lower.includes('revised');
    default:
      return true;
  }
}

const EXCLUDE_PRODUCT_PATTERNS = [
  /\bbox\b/i,
  /\betb\b/i,
  /\belite\s*trainer/i,
  /\bcase\b/i,
  /\bdisplay\b/i,
  /\bbundle\b/i,
  /\bcollection\b/i,
  /\btin\b/i,
];

function isBoosterPack(productName: string): boolean {
  const lower = productName.toLowerCase();
  if (!lower.includes('booster pack') && !lower.includes('booster')) return false;
  return !EXCLUDE_PRODUCT_PATTERNS.some((p) => p.test(productName));
}

// Accepted product types for booster packs (empty string = unknown, allowed as fallback)
const VALID_PRODUCT_TYPES = ['Booster Pack', 'Sealed Products', ''];

export interface MatchResult {
  product: TCGPlayerSearchResult;
  confidence: number;
  reasons: string[];
}

function scoreMatch(
  result: TCGPlayerSearchResult,
  setName: string,
  edition?: Edition | null
): MatchResult {
  const reasons: string[] = [];
  let score = 0;

  const setLower = setName.toLowerCase();
  const resultSetLower = result.setName.toLowerCase();
  const resultNameLower = result.productName.toLowerCase();

  // Also try matching against TCGPlayer set name with prefix stripped
  const strippedSetLower = resultSetLower.replace(TCGPLAYER_SET_PREFIXES, '').trim();

  // Set name matching (0-0.5)
  if (resultSetLower === setLower || strippedSetLower === setLower) {
    score += 0.5;
    reasons.push('exact set name match');
  } else if (
    resultSetLower.startsWith(setLower + ' ') ||
    resultSetLower.startsWith(setLower + ':') ||
    strippedSetLower.startsWith(setLower + ' ') ||
    strippedSetLower.startsWith(setLower + ':')
  ) {
    score += 0.3;
    reasons.push('set name starts-with match');
  } else if (
    resultSetLower.endsWith(' ' + setLower) ||
    strippedSetLower.endsWith(' ' + setLower)
  ) {
    // Catches "SV: Scarlet & Violet 151" matching "151"
    score += 0.4;
    reasons.push('set name ends-with match');
  } else if (resultSetLower.includes(setLower) || strippedSetLower.includes(setLower)) {
    score += 0.1;
    reasons.push('loose set name match');
  } else {
    reasons.push('no set name match');
  }

  // Product name contains set name (0-0.2)
  if (resultNameLower.includes(setLower)) {
    score += 0.2;
    reasons.push('product name contains set name');
  }

  // Edition match (0-0.2)
  if (matchesEdition(result.productName, edition)) {
    score += 0.2;
    reasons.push('edition match');
  }

  // Has market price (0-0.1)
  if (result.marketPrice != null && result.marketPrice > 0) {
    score += 0.1;
    reasons.push('has market price');
  }

  return { product: result, confidence: Math.min(score, 1), reasons };
}

export interface TCGPlayerSearchResult {
  productId: number;
  productName: string;
  marketPrice: number | null;
  lowestPrice: number | null;
  imageUrl: string;
  setName: string;
  productUrlName: string;
}

export async function searchProducts(
  query: string
): Promise<TCGPlayerSearchResult[]> {
  try {
    const res = await fetch(`${BASE_URL}/search/request?q=${encodeURIComponent(query)}&isList=false`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      body: JSON.stringify({
        algorithm: '',
        from: 0,
        size: 50,
        filters: {
          term: {
            productLineName: ['pokemon'],
          },
          range: {},
          match: {},
        },
        listingSearch: {
          filters: {
            term: {},
            range: {},
            exclude: { channelExclusion: 0 },
          },
          context: { cart: {} },
        },
        context: { cart: {}, shippingCountry: 'US' },
        settings: {},
        sort: {},
        query,
      }),
    });

    if (!res.ok) return [];

    const data = await res.json();
    const results: TCGPlayerSearchResult[] = [];

    const resultSets = data?.results;
    if (!Array.isArray(resultSets)) return [];

    for (const resultSet of resultSets) {
      const aggregations = resultSet?.aggregations;
      if (!aggregations) continue;

      // The search response nests results in aggregations
      const totalResults = resultSet?.totalResults ?? 0;
      if (totalResults === 0) continue;

      // Results are in the main results array
      const items = resultSet?.results;
      if (!Array.isArray(items)) continue;

      for (const item of items) {
        results.push({
          productId: item.productId,
          productName: item.productName ?? '',
          marketPrice: item.marketPrice ?? null,
          lowestPrice: item.lowestPrice ?? null,
          imageUrl: getProductImageUrl(item.productId),
          setName: item.setName ?? '',
          productUrlName: item.productUrlName ?? '',
        });
      }
    }

    return results;
  } catch {
    return [];
  }
}

