export function isVintagePack(setName: string, edition?: Edition | null): boolean {
  const key = `${setName}|${edition ?? ''}`;
  return key in VINTAGE_PACK_IDS;
}

export interface FindPackResult {
  result: TCGPlayerSearchResult;
  confidence: number;
}

// Build a list of search queries to try, from most specific to broadest
function buildSearchQueries(setName: string, edition?: Edition | null): string[] {
  const editionTerms = getEditionSearchTerms(edition);
  const queries: string[] = [];

  // If we have a TCGPlayer alias for this set, try that first
  const alias = tcgplayerSetMap[setName];
  if (alias && alias !== setName) {
    queries.push(`pokemon ${alias} booster pack${editionTerms}`);
  }

  // Primary query with "pokemon" prefix (like the research script uses)
  queries.push(`pokemon ${setName} booster pack${editionTerms}`);

  // Without "pack" — some products are just listed as "booster"
  queries.push(`pokemon ${setName} booster${editionTerms}`);

  // Reordered — sometimes helps with search relevance
  queries.push(`${setName} pokemon booster pack${editionTerms}`);

  return queries;
}

// Try to find the best match from a set of search results
function findBestCandidate(
  results: TCGPlayerSearchResult[],
  setName: string,
  edition?: Edition | null
): MatchResult | null {
  const candidates = results.filter(
    (r) => isBoosterPack(r.productName) && matchesEdition(r.productName, edition)
  );

  if (candidates.length === 0) return null;

  const scored = candidates
    .map((c) => scoreMatch(c, setName, edition))
    .sort((a, b) => b.confidence - a.confidence);

  return scored[0].confidence >= 0.5 ? scored[0] : null;
}

export async function findPackProduct(
  setName: string,
  edition?: Edition | null
): Promise<FindPackResult | null> {
  // Check hardcoded vintage mapping first
  const key = `${setName}|${edition ?? ''}`;
  const vintageId = VINTAGE_PACK_IDS[key];
  if (vintageId) {
    const details = await getProductDetails(vintageId);
    if (details) {
      // Validate product type for vintage packs too
      if (details.productTypeName && !VALID_PRODUCT_TYPES.includes(details.productTypeName)) {
        // Product type mismatch — skip this vintage mapping
      } else {
        return {
          result: {
            productId: vintageId,
            productName: details.productName,
            marketPrice: details.marketPrice,
            lowestPrice: details.lowestPrice,
            imageUrl: getProductImageUrl(vintageId),
            setName: details.setName,
            productUrlName: details.productUrlName,
          },
          confidence: 1.0, // hardcoded IDs are pre-verified
        };
      }
    }
  }

  // Try multiple search queries, stop as soon as we get a good match
  const queries = buildSearchQueries(setName, edition);
  let bestOverall: MatchResult | null = null;

  for (const query of queries) {
    const results = await searchProducts(query);
    const best = findBestCandidate(results, setName, edition);

    if (best) {
      // Keep track of the best match across all queries
      if (!bestOverall || best.confidence > bestOverall.confidence) {
        bestOverall = best;
      }
      // Stop early if we found a high-confidence match
      if (best.confidence >= 0.7) break;
    }
  }

  if (!bestOverall) return null;

  // Validate product type via details endpoint
  const details = await getProductDetails(bestOverall.product.productId);
  if (details?.productTypeName && !VALID_PRODUCT_TYPES.includes(details.productTypeName)) {
    // Wrong product type — this match is invalid
    return null;
  }

  return { result: bestOverall.product, confidence: bestOverall.confidence };
}
